from typing import Dict

def fib(n: int, memo: Dict[int, int] = None) -> int:
    """
    Returns the nth Fibonacci number using memoization.

    fib(0) = 0
    fib(1) = 1
    """
    if memo is None:
        memo = {}

    if n in memo:
        return memo[n]

    if n == 0:
        return 0
    elif n == 1:
        return 1
    else:
        # Recursive step with memoization
        memo[n] = fib(n - 1, memo) + fib(n - 2, memo)
        return memo[n]

